"use client";

import { useState } from "react";
import usePlacesAutocomplete, { getGeocode, getLatLng, getZipCode } from "use-places-autocomplete";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";

export function StepLocation({ onComplete }: { onComplete: () => void }) {
  const [locationName, setLocationName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const {
    ready,
    value: addressInput,
    suggestions: { status, data: predictions },
    setValue: setAddressInput,
    clearSuggestions,
  } = usePlacesAutocomplete({
    requestOptions: { types: ["address"] },
    debounce: 300,
  });

  const [selectedAddress, setSelectedAddress] = useState<{
    description: string;
    placeId: string;
    address: string;
    city: string;
    state: string;
    zip: string;
    lat: number;
    long: number;
  } | null>(null);

  async function handleSelectPrediction(description: string, placeId: string) {
    setAddressInput(description, false);
    clearSuggestions();

    try {
      const results = await getGeocode({ placeId });
      const result = results[0];
      const { lat, lng } = await getLatLng(result);
      const zip = getZipCode(result, false) ?? "";

      const get = (type: string) =>
        result.address_components.find((c) => c.types.includes(type))?.long_name ?? "";
      const getShort = (type: string) =>
        result.address_components.find((c) => c.types.includes(type))?.short_name ?? "";

      const streetNumber = get("street_number");
      const route = get("route");
      const address = [streetNumber, route].filter(Boolean).join(" ");
      const city = get("locality") || get("sublocality") || get("administrative_area_level_2");
      const state = getShort("administrative_area_level_1");

      setSelectedAddress({ description, placeId, address, city, state, zip, lat, long: lng });
    } catch {
      toast.error("Failed to load address details. Please try again.");
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();

    if (!locationName.trim()) {
      toast.error("Please enter a location name.");
      return;
    }

    if (!selectedAddress) {
      toast.error("Please select an address from the suggestions.");
      return;
    }

    setIsSubmitting(true);

    try {
      const res = await fetch("/api/onboarding/location", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: locationName.trim(),
          address: selectedAddress.address,
          city: selectedAddress.city,
          state: selectedAddress.state,
          zip: selectedAddress.zip,
          lat: selectedAddress.lat,
          long: selectedAddress.long,
          geo_point: {
            type: "Point",
            coordinates: [selectedAddress.long, selectedAddress.lat],
          },
        }),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error ?? "Failed to save location");
      }

      onComplete();
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      <div>
        <h2 className="text-lg font-semibold">Add Your Location</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Tell us about the location where you'll install your CETV screen.
        </p>
      </div>

      <div className="space-y-2">
        <Label htmlFor="locationName">Location Name</Label>
        <Input
          id="locationName"
          placeholder="e.g. Main Street Cafe"
          value={locationName}
          onChange={(e) => setLocationName(e.target.value)}
          required
        />
      </div>

      <div className="space-y-2 relative">
        <Label htmlFor="address">Address</Label>
        <Input
          id="address"
          placeholder="Start typing your address..."
          value={addressInput}
          disabled={!ready}
          onChange={(e) => {
            setAddressInput(e.target.value);
            setSelectedAddress(null);
          }}
          autoComplete="off"
        />
        {status === "OK" && predictions.length > 0 && (
          <ul className="absolute z-50 w-full bg-popover border border-border rounded-md shadow-md mt-1 max-h-60 overflow-auto">
            {predictions.map((p) => (
              <li
                key={p.place_id}
                className="px-3 py-2 text-sm cursor-pointer hover:bg-accent hover:text-accent-foreground"
                onMouseDown={() => handleSelectPrediction(p.description, p.place_id)}
              >
                {p.description}
              </li>
            ))}
          </ul>
        )}
      </div>

      <Button type="submit" className="w-full" disabled={isSubmitting}>
        {isSubmitting ? "Saving..." : "Continue"}
      </Button>
    </form>
  );
}
